/**
 * @name XSS: Unencoded user input in HTTP error responses
 * @description Request URI/path or parameters echoed in error responses without HTML encoding
 * @kind path-problem
 * @problem.severity error
 * @id java/xss-error-response
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module XssErrorConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // HttpServletRequest methods
    exists(MethodCall mc |
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet.http", "HttpServletRequest") and
      mc.getMethod().hasName(["getParameter", "getHeader", "getRequestURI", "getPathInfo", "getQueryString", "getRequestURL", "getServletPath"]) and
      source.asExpr() = mc
    )
    or
    // com.sun.net.httpserver Exchange request URI
    exists(MethodCall mc |
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("com.sun.net.httpserver", "HttpExchange") and
      mc.getMethod().hasName(["getRequestURI", "getRequestHeaders"]) and
      source.asExpr() = mc
    )
    or
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // PrintWriter write/println
    exists(MethodCall mc |
      mc.getMethod().hasName(["write", "println", "print"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "Writer") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // HttpExchange sendResponseHeaders / response body
    exists(MethodCall mc |
      mc.getMethod().hasName(["write", "print", "println"]) and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // String used in response body construction
    exists(MethodCall mc |
      mc.getMethod().hasName("getResponseBody") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("com.sun.net.httpserver", "HttpExchange") and
      sink.asExpr() = mc
    )
  }
}

module XssErrorFlow = TaintTracking::Global<XssErrorConfig>;
import XssErrorFlow::PathGraph

from XssErrorFlow::PathNode source, XssErrorFlow::PathNode sink
where XssErrorFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential XSS: user-controlled data from $@ flows to HTTP response without encoding.", source.getNode(), "user-controlled input"

/**
 * @name Jolokia callback parameter reflected in response (JSONP XSS)
 * @description JSONP callback parameter reflected in response without encoding
 * @kind path-problem
 * @problem.severity error
 * @id java/xss-jsonp-callback
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module JsonpXssConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // getParameter("callback") or similar JSONP pattern
    exists(MethodCall mc |
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet.http", "HttpServletRequest") and
      mc.getMethod().hasName("getParameter") and
      source.asExpr() = mc
    )
    or
    // com.sun.net.httpserver URI query params
    exists(MethodCall mc |
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("com.sun.net.httpserver", "HttpExchange") and
      mc.getMethod().hasName("getRequestURI") and
      source.asExpr() = mc
    )
    or
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName(["write", "println", "print"]) and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "Writer") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "OutputStream")
      ) and
      sink.asExpr() = mc.getAnArgument()
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    // HTML encoding methods
    exists(MethodCall mc |
      mc.getMethod().hasName(["escapeHtml", "escape", "encode", "encodeForHTML", "htmlEncode"]) and
      node.asExpr() = mc
    )
  }
}

module JsonpXssFlow = TaintTracking::Global<JsonpXssConfig>;
import JsonpXssFlow::PathGraph

from JsonpXssFlow::PathNode source, JsonpXssFlow::PathNode sink
where JsonpXssFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "JSONP/reflected XSS: user-controlled data from $@ written to response.", source.getNode(), "request input"

/**
 * @name Jolokia: request URI/path info reflected in error response (HTTP handler)
 * @description Request URI or path info is included in error response body, potentially enabling XSS
 * @kind path-problem
 * @problem.severity error
 * @id java/xss-request-uri-in-error
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking

module UriXssConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // HttpServletRequest URI/path methods
    exists(MethodCall mc |
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet.http", "HttpServletRequest") and
      mc.getMethod().hasName(["getRequestURI", "getPathInfo", "getServletPath", "getQueryString", "getRequestURL"]) and
      source.asExpr() = mc
    )
    or
    // com.sun.net.httpserver URI
    exists(MethodCall mc |
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("com.sun.net.httpserver", "HttpExchange") and
      mc.getMethod().hasName("getRequestURI") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName(["write", "println", "print"]) and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "PrintWriter") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "OutputStream") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "Writer")
      ) and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // sendError with message
    exists(MethodCall mc |
      mc.getMethod().hasName("sendError") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet.http", "HttpServletResponse") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module UriXssFlow = TaintTracking::Global<UriXssConfig>;
import UriXssFlow::PathGraph

from UriXssFlow::PathNode source, UriXssFlow::PathNode sink
where UriXssFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "XSS via request URI: URI data from $@ flows to HTTP response.", source.getNode(), "request URI"

/**
 * @name Jolokia JSONP callback parameter in response - precise taint flow
 * @description The 'callback' query parameter value is embedded directly in JavaScript response as function name
 * @kind path-problem
 * @problem.severity error
 * @id java/xss-jsonp-callback-precise
 * @tags security
 *       external/cwe/cwe-079
 *       external/cwe/cwe-116
 */

import java
import semmle.code.java.dataflow.TaintTracking

module JsonpCallbackConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Parameter lookup via ConfigKey - specifically callback
    exists(MethodCall mc |
      mc.getMethod().hasName(["getParameter", "getKeyValue", "get"]) and
      mc.getEnclosingCallable().getDeclaringType().getPackage().getName().matches("org.jolokia%") and
      source.asExpr() = mc
    )
    or
    // URI-based parameter extraction
    exists(MethodCall mc |
      mc.getMethod().hasName(["getQuery", "getRawQuery"]) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Written to response OutputStream
    exists(MethodCall mc |
      mc.getMethod().hasName("write") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "OutputStream") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Written to response PrintWriter
    exists(MethodCall mc |
      mc.getMethod().hasName(["write", "println", "print"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "PrintWriter") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module JsonpCallbackFlow = TaintTracking::Global<JsonpCallbackConfig>;
import JsonpCallbackFlow::PathGraph

from JsonpCallbackFlow::PathNode source, JsonpCallbackFlow::PathNode sink
where JsonpCallbackFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "JSONP XSS: parameter from $@ flows to response output without encoding.", source.getNode(), "parameter value"

/**
 * @name Jolokia JSONP callback parameter flows into content.getBytes() in sendAllJSON
 * @description Callback query parameter is embedded in response content without encoding
 * @kind path-problem
 * @problem.severity error
 * @id java/xss-callback-content-bytes
 * @tags security
 *       external/cwe/cwe-079
 *       external/cwe/cwe-116
 */

import java
import semmle.code.java.dataflow.TaintTracking

module CallbackContentConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // URI query string parsed in ParsedUri
    exists(MethodCall mc |
      mc.getMethod().hasName(["getQuery", "getRawQuery"]) and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.net", "URI") and
      source.asExpr() = mc
    )
    or
    // getParameter from HttpServletRequest
    exists(MethodCall mc |
      mc.getMethod().hasName("getParameter") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet", "ServletRequest") and
      source.asExpr() = mc
    )
    or
    // getKeyValue (parameter map lookup) from ParsedUri
    exists(MethodCall mc |
      mc.getMethod().hasName("getKeyValue") and
      mc.getEnclosingCallable().getDeclaringType().getPackage().getName().matches("org.jolokia%") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // content.getBytes() call in sendAllJSON
    exists(MethodCall mc |
      mc.getMethod().hasName("getBytes") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "String") and
      mc.getEnclosingCallable().hasName("sendAllJSON") and
      sink.asExpr() = mc.getQualifier()
    )
    or
    // write(byte[]) to OutputStream in sendAllJSON
    exists(MethodCall mc |
      mc.getMethod().hasName("write") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "OutputStream") and
      mc.getEnclosingCallable().hasName("sendAllJSON") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module CallbackContentFlow = TaintTracking::Global<CallbackContentConfig>;
import CallbackContentFlow::PathGraph

from CallbackContentFlow::PathNode source, CallbackContentFlow::PathNode sink
where CallbackContentFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "JSONP XSS: callback/parameter from $@ directly embedded in response body via getBytes().", source.getNode(), "HTTP request parameter"
